/// <summary>
///  The <c>ETGOTMSalesLineWritePostSuperInputContract</c> class is used as data contract for the <c>SalesTableForm</c> class.
/// </summary>
class ETGOTMSalesLineWritePostSuperInputContract implements SysPackable
{
    SalesTable          salesTable;
    DialogButton        copyTaxGroupToMarkupTrans;
    boolean             updatePendingRegistrationsNonStocked;
    boolean             salesTableCheckUpdate;
    SalesLine           salesLine;
    container           salesLinePacked;
    container           salesTablePacked;
    TaxGroup            origTaxGroup;
    private DialogButton copyOverrideSalesTaxToMarkupTrans;

    #define.CurrentVersion(2)

    #localmacro.CurrentList
        updatePendingRegistrationsNonStocked,
        copyTaxGroupToMarkupTrans,
        copyOverrideSalesTaxToMarkupTrans,
        salesTableCheckUpdate,
        salesTablePacked,
        salesLinePacked,
        origTaxGroup
    #endmacro

}

Method.Source:
public container pack()
{
    salesTablePacked = buf2Con(salesTable,true);
    salesLinePacked  = buf2Con(salesLine,true);
    return [#CurrentVersion,#CurrentList];
}

public DialogButton parmCopyTaxGroupToMarkupTrans(DialogButton _copyTaxGroupToMarkupTrans = copyTaxGroupToMarkupTrans)
{
    copyTaxGroupToMarkupTrans = _copyTaxGroupToMarkupTrans;
    return copyTaxGroupToMarkupTrans;
}

public DialogButton parmCopyOverrideSalesTaxToMarkupTrans(DialogButton _copyOverrideSalesTaxToMarkupTrans = copyOverrideSalesTaxToMarkupTrans)
{
    copyOverrideSalesTaxToMarkupTrans = _copyOverrideSalesTaxToMarkupTrans;
    return copyOverrideSalesTaxToMarkupTrans;
}

public TaxGroup parmOrigTaxGroup(TaxGroup _origTaxGroup = origTaxGroup)
{
    origTaxGroup = _origTaxGroup;
    return origTaxGroup;
}

public SalesLine parmSalesLine (SalesLine _salesLine = salesLine)
{
    salesLine = _salesLine;
    return salesLine;
}

public SalesTable parmSalesTable (SalesTable _salesTable = salesTable)
{
    salesTable = _salesTable;
    return salesTable;
}

public boolean parmSalesTableCheckUpdate (boolean _salesTableCheckUpdate = salesTableCheckUpdate)
{
    salesTableCheckUpdate = _salesTableCheckUpdate;
    return salesTableCheckUpdate;
}

public boolean parmUpdatePendingRegistrationsNonStocked (boolean _updatePendingRegistrationsNonStocked = updatePendingRegistrationsNonStocked)
{
    updatePendingRegistrationsNonStocked = _updatePendingRegistrationsNonStocked;
    return updatePendingRegistrationsNonStocked;
}

public boolean unpack(container _packedClass)
{
    int version     = RunBase::getVersion(_packedClass);

    switch (version)
    {
        case #CurrentVersion:
            [version,#CurrentList] = _packedClass;
            con2Buf(salesTablePacked,salesTable);
            con2Buf(salesLinePacked,salesLine);
            return true;
        default :
            return false;
    }
}

/// <summary>
///     Creates an instance of the <c>ETGOTMSalesLineWritePostSuperInputContract</c> class based on a container from a prior call to <c>SalesLineWritePostSuperInputContract.pack</c> method.
/// </summary>
/// <param name="_packedClass">
///     A <c>Container</c> holding the packed class.
/// </param>
/// <returns>
///     An instance of the <c>ETGOTMSalesLineWritePostSuperInputContract</c> class identical to the one that was packed into the <c>container</c>.
/// </returns>
static public ETGOTMSalesLineWritePostSuperInputContract create(container _packedClass)
{
    ETGOTMSalesLineWritePostSuperInputContract salesLineWritePostSuperInputContract = ETGOTMSalesLineWritePostSuperInputContract::construct();
    salesLineWritePostSuperInputContract.unpack(_packedClass);
    return salesLineWritePostSuperInputContract;
}
